with:
  # optional units for numeric values
      unit_map = {
          "elevationAboveTheSeaLevel": "metres",
          "elevationAboveTheSeaLevelInFeet": "feet",
          "elevationAboveTheSeaLevelInMetres": "metres",
          "runwayLength": "metres",
          "1stRunwayLengthFeet": "feet",
          "1stRunwayLengthMetre": "metres",
          "4thRunwayLengthFeet": "feet",
          "3rdRunwayLengthFeet": "feet",
          "5thRunwaySurfaceType": "",  # no unit
      }
      for t in triples:
          verb = verb_map.get(t.predicate, f"has {t.predicate}")
          obj = t.object
          # try to add unit if object looks numeric and a unit is defined
          try:
              num = float(obj)
              unit = unit_map.get(t.predicate, "")
              if unit:
                  # remove trailing .0 if integer
                  if num.is_integer():
                      obj = f"{int(num)} {unit}"
                  else:
                      obj = f"{num:g} {unit}"
          except (ValueError, TypeError):
              pass
          phrase = f"{verb} {obj}"
          subject_map.setdefault(t.subject, []).append(phrase)
