with:
  if not clauses:
          return ""
      # Build a single complex sentence from all clauses
      if len(clauses) == 1:
          return clauses[0] + "."
      else:
          # join with commas and an 'and' before the final clause
          if len(clauses) == 2:
              sentence = " and ".join(clauses)
          else:
              sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1]
          return sentence + "."
